    private void ExtractSettings(XmlNode node, Dictionary<string, string> settings)
    {
        if (node == null) return;
        
        if (node.NodeType == XmlNodeType.Element)
        {
            if (node.Name == "setting" || node.Name == "property" || node.Name == "config")
            {
                XmlAttribute keyAttr = node.Attributes["key"] ?? node.Attributes["name"];
                XmlAttribute valueAttr = node.Attributes["value"];
                
                if (keyAttr != null)
