                    string key = keyAttr.Value;
                    string value = valueAttr?.Value ?? node.InnerText;
                    
                    if (!string.IsNullOrEmpty(key))
                    {
                        settings[key] = value;
                    }
                }
            }
        }
        
        foreach (XmlNode childNode in node.ChildNodes)
        {
            ExtractSettings(childNode, settings);
        }
    }
